test_traj:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index fa05b8dd2242..d237233a04ab 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -5549,6 +5549,28 @@ InstructionCost LoopVectorizationCostModel::expectedCost(ElementCount VF) {
     Cost += BlockCost;
   }

+  // Add the cost of instructions that are needed for the computation of the
+  // trip count.
+  if (Value *TC = L->getTripCount()) {
+    SmallVector<const Value *, 4> Worklist;
+    Worklist.push_back(TC);
+    SmallPtrSet<const Value *, 4> Visited;
+    while (!Worklist.empty()) {
+      const Value *V = Worklist.pop_back_val();
+      if (!Visited.insert(V).second)
+        continue;
+      if (auto *I = dyn_cast<Instruction>(V)) {
+        if (!L->isLoopInvariant(I))
+          continue;
+        // This is a loop invariant instruction that is used to compute the
+        // trip count. Add its cost to the prolog.
+        Cost += getInstructionCost(I, VF);
+        for (const Value *Op : I->operands())
+          Worklist.push_back(Op);
+      }
+    }
+  }
+
   return Cost;
 }

